 58→## Example 2: Section with Local State
 59→
 60→A section that manages its own UI state with `useState`.
 61→
 62→**`src/components/sections/CounterSection.tsx`**
 63→```tsx
 64→interface Props {
 65→  count: number;
 66→  onIncrement: () => void;
 67→  counterPressed: boolean;
 68→  counterCanvasRef: React.RefObject<HTMLCanvasElement | null>;
 69→  onCounterMouseEnter: () => void;
 70→  onCounterMouseLeave: () => void;
 71→  onCounterMouseDown: () => void;
 72→  onCounterMouseUp: () => void;
 73→}
 74→export default function CounterSection(props: Props) {
 75→  return (
 76→    <section className="section-card counter-section">
 77→      <h3>Counter</h3>
 78→      <p className="counter-value">{props.count}</p>
 79→      <div className="counter-buttons">
 80→        <button
 81→          type="button"
 82→          className="esc-option-preview counter-btn"
 83→          onMouseEnter={props.onCounterMouseEnter}
 84→          onMouseLeave={props.onCounterMouseLeave}
 85→          onMouseDown={() => {
 86→            props.onCounterMouseDown();
 87→            props.onIncrement();
 88→          }}
 89→          onMouseUp={props.onCounterMouseUp}
 90→        >
 91→          <canvas ref={props.counterCanvasRef} className="esc-option-canvas" />
 92→          <span
 93→            className="esc-option-label"
 94→            style={{
 95→              transform: props.counterPressed ? "translate(2px, 2px)" : "none",
 96→            }}
 97→          >
 98→            +1
 99→          </span>
100→        </button>
101→      </div>
102→    </section>
103→  );
104→}
