195→## Example 3: Global State Store
196→
197→When state needs to be shared between sections or accessed outside React, use the external store pattern.
198→
199→**`src/state/counter.ts`**
200→```ts
201→import { createExternalStore } from './createStore';
202→
203→// --- Stores ---
204→const countStore = createExternalStore<number>(0);
205→
206→// --- Non-reactive getters (use anywhere) ---
207→export const getCount = countStore.get;
208→
209→// --- Setters (use anywhere) ---
210→export const setCount = countStore.set;
211→
212→// --- Helper actions ---
213→export function increment() {
214→  countStore.set(prev => prev + 1);
215→}
216→export function decrement() {
217→  countStore.set(prev => prev - 1);
218→}
219→export function reset() {
220→  countStore.set(0);
221→}
222→
223→// --- Hooks (use in React components only) ---
224→export const useCount = countStore.useValue;
225→```
226→
227→**Using the store in a section:**
228→```tsx
229→import { useCount, increment, decrement, reset } from '../../state/counter';
230→
231→export default function CounterSection() {
232→  const count = useCount(); // reactive — re-renders when count changes
233→
234→  return (
235→    <section className="section-card counter-section">
236→      <h3>Count: {count}</h3>
237→      <button type="button" onClick={decrement}>−</button>
238→      <button type="button" onClick={increment}>+</button>
239→      <button type="button" onClick={reset}>Reset</button>
240→    </section>
241→  );
242→}
243→```
244→
245→**Using the store outside React** (e.g., from a timer callback):
246→```ts
247→import { getCount, setCount } from './state/counter';
248→
249→setInterval(() => {
250→  const current = getCount(); // read without subscribing
251→  setCount(current + 1);      // write — triggers re-renders in subscribed components
252→}, 1000);
253→```
