288→## Example 5: Timer with setInterval
289→
290→A section with a running timer — the pattern for the build order timer.
291→
292→**`src/state/timer.ts`**
293→```ts
294→import { createExternalStore } from './createStore';
295→
296→const runningStore = createExternalStore<boolean>(false);
297→const elapsedStore = createExternalStore<number>(0); // seconds
298→
299→let intervalId: ReturnType<typeof setInterval> | null = null;
300→
301→export function startTimer() {
302→  if (runningStore.get()) return; // already running
303→  runningStore.set(true);
304→  intervalId = setInterval(() => {
305→    elapsedStore.set(prev => prev + 1);
306→  }, 1000);
307→}
308→
309→export function pauseTimer() {
310→  if (intervalId !== null) {
311→    clearInterval(intervalId);
312→    intervalId = null;
313→  }
