 6→let intervalId: ReturnType<typeof setInterval> | null = null;
 7→
 8→export function startTimer() {
 9→  if (runningStore.get()) return; // already running
10→  runningStore.set(true);
11→  intervalId = setInterval(() => {
12→    elapsedStore.set((prev) => prev + 1);
13→  }, 1000);
14→}
